Three packages, one model
Each package below fits the same two-stage model against the same frozen snapshot, through the shared fit_nairu() contract. What differs is how each package likes its state space handed to it — and, as a direct consequence, how much of the parameter vector each one’s own optimizer searches over.

MARSS: explicit matrices, one estimated element per cell
MARSS wants a fully-specified list of matrices (B, U, Q, Z, A, R, plus D/d for regression effects), where any cell can be a fixed number or a character label naming a free parameter — mix and match freely within a matrix. It’s the most literal translation of the algebra above onto code.
The one thing MARSS’s shorthand doesn’t support is tying a free parameter across two different top-level matrices — which is exactly what “\(Q\) equals \(R\)” (this post’s reparametrization) asks for. So fit_nairu_marss() profiles the shared variance in an outer 1-D search, and lets MARSS’s own estimator handle \(\beta,\gamma\) (or just \(\theta\), in stage 2) conditional on each candidate variance — the reason MARSS’s runtime in the comparison table below is visibly the largest of the three.

suppressMessages(library(MARSS))

# MARSS wants a fully-specified list of matrices, where any cell is either a
# fixed number or a character label naming a free parameter. It has no way
# to tie a free parameter across two *different* top-level matrices, though
# — which is exactly what this model's "Q equals R" reparametrization needs.
# So the shared variance is profiled in an outer 1-D search, and MARSS's own
# estimator handles beta/gamma (or just theta, in stage 2) conditional on
# each candidate variance. That's also why this backend is the slowest of
# the three in the runtime comparison below.
fit_nairu_marss &lt;- function(reg, lambda, fixed = NULL) {
  Zt &lt;- matrix(1 / sqrt(lambda))
  y &lt;- matrix(reg$y2, nrow = 1)

  if (is.null(fixed)) {
    d &lt;- t(cbind(reg$xtilde, -reg$u))
    D_labels &lt;- list("beta", "gamma")
  } else {
    d &lt;- t(cbind(reg$xtilde, -reg$u, reg$ippcv))
    D_labels &lt;- list(fixed$beta, fixed$gamma, "theta")
  }
  D &lt;- matrix(D_labels, nrow = 1)

  fit_given_sigma2 &lt;- function(sigma2) {
    mod &lt;- list(
      B = matrix(1), U = matrix(0), Q = matrix(sigma2),
      Z = Zt, A = matrix(0), R = matrix(sigma2),
      D = D, d = d,
      x0 = matrix(0), tinitx = 0, V0 = matrix(DIFFUSE_VAR)
    )
    MARSS(y, model = mod, silent = TRUE, control = list(maxit = 1000))
  }
  negloglik &lt;- function(log_sigma2) {
    fit &lt;- tryCatch(fit_given_sigma2(exp(log_sigma2)), error = function(e) NULL)
    if (is.null(fit) || !is.finite(fit$logLik)) return(LOGLIK_PENALTY)
    -fit$logLik
  }

  t0 &lt;- Sys.time()
  opt &lt;- optimize(negloglik, interval = log(c(1e-3, 100)), tol = 1e-4)
  fit &lt;- fit_given_sigma2(exp(opt$minimum))
  runtime &lt;- as.numeric(Sys.time() - t0, units = "secs")

  cf &lt;- coef(fit)$D
  if (is.null(fixed)) {
    beta &lt;- cf[1]; gamma &lt;- cf[2]; theta &lt;- NA_real_
  } else {
    beta &lt;- fixed$beta; gamma &lt;- fixed$gamma; theta &lt;- cf[1]
  }
  s_t &lt;- as.numeric(MARSSkfss(fit)$xtT)

  assemble_result(beta, gamma, theta, reg, s_t, lambda, fit$logLik, runtime)
}



KFAS: formulas, and regression coefficients concentrated out
KFAS builds models from a formula (SSMtrend(), SSMregression()), and its exact diffuse initialization lets regression coefficients (here, \(\beta,\gamma\) or \(\theta\)) be concentrated out of the likelihood entirely — treated as diffuse states with zero process variance, solved via generalized least squares inside the same filter pass that estimates the NAIRU. The only thing left for fitSSM()’s outer optimizer to search over is the single shared variance parameter — which is why KFAS’s runtime below is the smallest of the three, despite estimating exactly the same model.
The one manual step is overriding the trend component’s default loading (KFAS assumes 1) to this post’s known \(1/\sqrt{\lambda}\):

suppressMessages(library(KFAS))

# KFAS builds models from a formula, and its exact diffuse initialization
# lets regression coefficients (beta/gamma, or theta in stage 2) be
# concentrated out of the likelihood entirely -- solved via GLS inside the
# same filter pass that estimates the NAIRU, rather than searched over by
# an outer optimizer. The only thing fitSSM()'s optimizer has to search is
# the single shared variance parameter, which is why this backend is the
# fastest of the three in the runtime comparison below.
fit_nairu_kfas &lt;- function(reg, lambda, fixed = NULL) {
  if (is.null(fixed)) {
    xtilde &lt;- reg$xtilde; u &lt;- reg$u
    mod &lt;- SSModel(reg$y2 ~ 0 + SSMregression(~ 0 + xtilde + u, Q = 0) +
      SSMtrend(1, Q = list(matrix(NA))), H = matrix(NA))
  } else {
    y3 &lt;- reg$y2 - fixed$beta * reg$xtilde + fixed$gamma * reg$u
    ippcv &lt;- reg$ippcv
    mod &lt;- SSModel(y3 ~ 0 + SSMregression(~ 0 + ippcv, Q = 0) +
      SSMtrend(1, Q = list(matrix(NA))), H = matrix(NA))
  }
  # KFAS's SSMtrend() assumes a loading of 1 by default; override it to this
  # model's known 1/sqrt(lambda) for every time point (Z is time-varying
  # here because the regression component makes the whole Z array 3-D).
  level_col &lt;- dim(mod$Z)[2]
  mod$Z[1, level_col, ] &lt;- 1 / sqrt(lambda)

  m &lt;- dim(mod$Q)[1]
  updatefn &lt;- function(pars, model) {
    sigma2 &lt;- exp(pars[1])
    model$H[1, 1, 1] &lt;- sigma2
    model$Q[m, m, 1] &lt;- sigma2 # tie Q to H: this model's "Q equals R"
    model
  }

  t0 &lt;- Sys.time()
  fit &lt;- fitSSM(mod, inits = log(1), updatefn = updatefn, method = "BFGS")
  runtime &lt;- as.numeric(Sys.time() - t0, units = "secs")

  smooth &lt;- KFS(fit$model, filtering = "state", smoothing = "state")
  cf &lt;- coef(smooth)
  loglik &lt;- -fit$optim.out$value

  if (is.null(fixed)) {
    beta &lt;- as.numeric(cf[nrow(cf), "xtilde"])
    gamma &lt;- -as.numeric(cf[nrow(cf), "u"])
    theta &lt;- NA_real_
  } else {
    beta &lt;- fixed$beta; gamma &lt;- fixed$gamma
    theta &lt;- as.numeric(cf[nrow(cf), "ippcv"])
  }
  s_t &lt;- as.numeric(cf[, "level"])

  assemble_result(beta, gamma, theta, reg, s_t, lambda, loglik, runtime)
}



kalmanfilter: bare matrices, roll your own optimizer
kalmanfilter is the most bare-bones of the three: one function, kalman_filter(ssm, yt), that runs the filter and hands back the log-likelihood — no built-in estimator at all. Every parameter, structural or variance, goes into a vector you optimize yourself (with optim(), maxLik, or anything else); every state-space matrix is built from that vector by hand, on every likelihood evaluation.

suppressMessages(library(kalmanfilter))

# kalmanfilter is the most bare-bones of the three: one function,
# kalman_filter(ssm, yt), that runs the filter and hands back the
# log-likelihood -- no built-in estimator at all. Every parameter, structural
# or variance, goes into a vector optimized by hand (with optim() here);
# every state-space matrix is rebuilt from that vector on every likelihood
# evaluation.
fit_nairu_kalmanfilter &lt;- function(reg, lambda, fixed = NULL) {
  n &lt;- length(reg$y2)
  yt &lt;- matrix(reg$y2, nrow = 1)

  build_ssm &lt;- function(par) {
    if (is.null(fixed)) {
      beta &lt;- par[["beta"]]; gamma &lt;- par[["gamma"]]
      ippcv_term &lt;- 0
    } else {
      beta &lt;- fixed$beta; gamma &lt;- fixed$gamma
      ippcv_term &lt;- par[["theta"]] * reg$ippcv
    }
    sigma2 &lt;- exp(par[["logsigma2"]])
    Am_t &lt;- beta * reg$xtilde - gamma * reg$u + ippcv_term
    list(
      Fm = array(1, dim = c(1, 1, n)),
      Dm = array(0, dim = c(1, 1, n)),
      Qm = array(sigma2, dim = c(1, 1, n)),
      Hm = array(1 / sqrt(lambda), dim = c(1, 1, n)),
      Am = array(Am_t, dim = c(1, 1, n)),
      Rm = array(sigma2, dim = c(1, 1, n)), # Q equals R: this model's signal-to-noise tie
      B0 = matrix(0), P0 = matrix(DIFFUSE_VAR)
    )
  }
  negloglik &lt;- function(par) {
    f &lt;- tryCatch(kalman_filter(build_ssm(par), yt), error = function(e) NULL)
    if (is.null(f) || !is.finite(f$lnl)) return(LOGLIK_PENALTY)
    -f$lnl
  }

  start &lt;- if (is.null(fixed)) {
    c(beta = 0.3, gamma = 0.6, logsigma2 = log(2))
  } else {
    c(theta = 1, logsigma2 = log(2))
  }

  t0 &lt;- Sys.time()
  opt &lt;- optim(start, negloglik, method = "BFGS")
  runtime &lt;- as.numeric(Sys.time() - t0, units = "secs")

  if (is.null(fixed)) {
    beta &lt;- opt$par[["beta"]]; gamma &lt;- opt$par[["gamma"]]; theta &lt;- NA_real_
  } else {
    beta &lt;- fixed$beta; gamma &lt;- fixed$gamma; theta &lt;- opt$par[["theta"]]
  }
  filt &lt;- kalman_filter(build_ssm(opt$par), yt, smooth = TRUE)
  s_t &lt;- as.numeric(filt$B_tt)

  assemble_result(beta, gamma, theta, reg, s_t, lambda, -opt$value, runtime)
}
